#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long A, B;
        scanf("%lld %lld", &A, &B);
        long long N = A + B;
        int possible = 0;
        if (N % 2 == 0) {
            if (A % 2 == 0 && B % 2 == 0 && A >= 2 && B >= 2) possible = 1;
        } else {
            if (A % 2 == 1 && B % 2 == 0 && A >= 3 && B >= 2) possible = 1;
            else if (B % 2 == 1 && A % 2 == 0 && B >= 3 && A >= 2) possible = 1;
        }
        printf("%s\n", possible ? "Yes" : "No");
    }
    return 0;
}

