#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it))
        N = A + B
        ok = False
        if N % 2 == 0:
            if A % 2 == 0 and B % 2 == 0 and A >= 2 and B >= 2:
                ok = True
        else:
            if A % 2 == 1 and B % 2 == 0 and A >= 3 and B >= 2:
                ok = True
            elif B % 2 == 1 and A % 2 == 0 and B >= 3 and A >= 2:
                ok = True
        out.append('Yes' if ok else 'No')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

